{
  "welcomeSubject": "Welcome to {{productName}}",
  "welcomeHtmlBody": "<!DOCTYPE html><html><head><meta charset=\"UTF-8\"/></head><body style=\"font-family:system-ui,sans-serif;max-width:560px;margin:0 auto;padding:24px;\"><p>Hi {{recipientName}},</p><p>Welcome to <strong>{{productName}}</strong>.</p><p><a href=\"{{dashboardUrl}}\" style=\"display:inline-block;background:#2563eb;color:#fff;padding:10px 18px;border-radius:8px;text-decoration:none;font-weight:600;\">Open dashboard</a></p><p style=\"font-size:13px;color:#64748b;\">If you did not create this account, ignore this email.</p></body></html>",
  "passwordResetSubject": "Reset your {{productName}} password",
  "passwordResetHtmlBody": "<!DOCTYPE html><html><head><meta charset=\"UTF-8\"/></head><body style=\"font-family:system-ui,sans-serif;max-width:560px;margin:0 auto;padding:24px;\"><p>Hi {{recipientName}},</p><p>Reset your password for <strong>{{productName}}</strong>.</p><p><a href=\"{{resetLink}}\" style=\"display:inline-block;background:#2563eb;color:#fff;padding:10px 18px;border-radius:8px;text-decoration:none;font-weight:600;\">Reset password</a></p><p style=\"font-size:13px;color:#64748b;\">Link expires in one hour.</p></body></html>",
  "additionalTemplates": [
    {
      "id": "email_verification",
      "subject": "Verify your {{productName}} email",
      "htmlBody": "<p>Hi {{recipientName}},</p><p><a href=\"{{verifyLink}}\">Verify email</a></p>"
    }
  ]
}
